/**
 * Ein erweiterbarer Dependency Injection Container.
 * Unterstützt Registrierung, Auflösung, automatische Instanziierung und Plugin-Erweiterungen.
 * Erweiterung: Qualifier- und Vererbungsunterstützung
 */
class DiContainer {
  constructor() {
    /** @type {Map<string, any>} */
    this.instances = new Map();

    /** @type {Map<string, Function>} */
    this.factories = new Map();

    /** @type {Map<string, Function[]>} */
    this.extensions = new Map(); // Erweiterungsprozessoren

    /** @type {Map<string, any>} */
    this.qualifiers = new Map(); // Qualifier-Instanzen
  }

  /**
   * Registriert eine Factory oder Klasse unter einem Namen.
   * Führt alle 'onRegister'-Erweiterungen aus.
   * @param {string} name
   * @param {Function} factory
   */
  register(name, factory) {
    this.factories.set(name, factory);

    const onRegister = this.extensions.get('onRegister') || [];
    onRegister.forEach(fn => fn(name, factory));
  }

  /**
   * Gibt eine Instanz zurück – erzeugt sie bei Bedarf oder liefert manuell gesetzte Instanz.
   * Führt alle 'onResolve'-Erweiterungen aus.
   * @param {string} name
   * @returns {any}
   */
  resolve(name) {
    if (this.instances.has(name)) {
      return this.instances.get(name);
    }

    const factory = this.factories.get(name);
    if (factory) {
      const instance = typeof factory === 'function' ? new factory() : factory;

      const onResolve = this.extensions.get('onResolve') || [];
      onResolve.forEach(fn => fn(name, instance));

      this.instances.set(name, instance);
      return instance;
    }

    throw new Error(`Keine Instanz oder Factory für "${name}" registriert`);
  }

  /**
   * Manuelles Setzen einer Instanz.
   * Führt alle 'onSet'-Erweiterungen aus.
   * @param {string} name
   * @param {any} instance
   */
  set(name, instance) {
    this.instances.set(name, instance);

    const onSet = this.extensions.get('onSet') || [];
    onSet.forEach(fn => fn(name, instance));
  }

  /**
   * Prüft, ob eine Instanz vorhanden ist.
   * @param {string} name
   * @returns {boolean}
   */
  has(name) {
    return this.instances.has(name);
  }

  /**
   * Leert den Container (für Tests).
   */
  reset() {
    this.instances.clear();
    this.factories.clear();
    this.extensions.clear();
    this.qualifiers.clear();
  }

  /**
   * Registriert eine Erweiterungsfunktion für einen bestimmten Typ.
   * Nur vom PluginLoader aufzurufen.
   * @param {string} type - z. B. 'onRegister', 'onResolve', 'onSet'
   * @param {Function} extensionFn
   */
  registerExtension(type, extensionFn) {
    if (!this.extensions.has(type)) {
      this.extensions.set(type, []);
    }
    this.extensions.get(type).push(extensionFn);
  }

  /**
   * Gibt alle Erweiterungen eines bestimmten Typs zurück.
   * @param {string} type
   * @returns {Function[]}
   */
  getExtensions(type) {
    return this.extensions.get(type) || [];
  }

  /**
   * Registriert eine Instanz unter einem Qualifier-Namen.
   * @param {string} qualifier
   * @param {any} instance
   */
  registerQualifier(qualifier, instance) {
    this.qualifiers.set(qualifier, instance);
  }

  /**
   * Gibt eine Instanz anhand eines Qualifiers zurück.
   * @param {string} qualifier
   * @returns {any}
   */
  resolveByQualifier(qualifier) {
    if (this.qualifiers.has(qualifier)) {
      return this.qualifiers.get(qualifier);
    }
    throw new Error(`Kein Qualifier "${qualifier}" registriert`);
  }
}

module.exports = new DiContainer();